import{_ as t,o,c as a,ag as r}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Brand","description":"","frontmatter":{},"headers":[],"relativePath":"brand.md","filePath":"brand.md","lastUpdated":1777921494000}'),s={name:"brand.md"};function i(d,e,n,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="brand" tabindex="-1">Brand <a class="header-anchor" href="#brand" aria-label="Permalink to &quot;Brand&quot;">​</a></h1><p><strong>Date locked:</strong> 2026-05-03 (rename baseline) <strong>Decision reference:</strong> <code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code> + <code>docs/superpowers/research/2026-05-03-zkqes-rename-analysis.md</code></p><p>A one-page reference for anyone writing public-facing copy, talks, slides, or third-party documentation about this project. Read once; carry forward.</p><h2 id="name" tabindex="-1">Name <a class="header-anchor" href="#name" aria-label="Permalink to &quot;Name&quot;">​</a></h2><p><strong><code>zkqes</code></strong> — lowercase noun, no expansion needed in casual use. Matches the domain (<code>zkqes.org</code>) and the descriptor.</p><p>When introducing the project to an outside reader who&#39;s seeing it for the first time, the two-second descriptor is <strong>&quot;a zero-knowledge proof of a qualified electronic signature&quot;</strong> (the literal expansion of zk-QES, eIDAS-aware audiences will recognize it). After the first use, just <code>zkqes</code>.</p><p>There is no protocol-vs-project-vs-descriptor split. The repo, the protocol, the website, the package scope, the CLI binary, the contract namespace — all named <code>zkqes</code>. One name, one thing.</p><h2 id="what-this-brand-reversed" tabindex="-1">What this brand REVERSED <a class="header-anchor" href="#what-this-brand-reversed" aria-label="Permalink to &quot;What this brand REVERSED&quot;">​</a></h2><p>The 2026-05-03 morning lock briefly used a three-tier hierarchy: <code>QKB</code> (protocol noun, structurally locked), <code>zk-QES</code> (descriptor), <code>Identity Escrow</code> (project umbrella). That decision was reversed the same day, on the explicit reasoning that:</p><ul><li>Nothing was actually shipped under the QKB name yet (zero npm publishes, zero contracts deployed, zero ceremony rounds run).</li><li>The three-name split was confusing for a single-thing project.</li><li>The cost of renaming was strictly minimal at this point in the lifecycle.</li></ul><p>So the structural rename to a single noun happened before any of those names left the repo. Future readers seeing this section can ignore the prior brand split entirely; it never reached production.</p><h2 id="how-to-write-about-the-project" tabindex="-1">How to write about the project <a class="header-anchor" href="#how-to-write-about-the-project" aria-label="Permalink to &quot;How to write about the project&quot;">​</a></h2><p><strong>Do:</strong></p><ul><li>Lead with the single name: &quot;zkqes is a zero-knowledge protocol over qualified electronic signatures.&quot;</li><li>Use <code>zkqes</code> in install commands, code references, contract addresses, ceremony command paths.</li><li>When invoking an outside reader, expand to &quot;a zero-knowledge proof of a qualified electronic signature (zk-QES)&quot; once at first introduction, then drop the expansion.</li></ul><p><strong>Don&#39;t:</strong></p><ul><li>Don&#39;t introduce additional names, sub-brands, or umbrella terms.</li><li>Don&#39;t reintroduce &quot;QKB&quot;, &quot;Qualified Key Binding&quot;, &quot;Identity Escrow&quot;, &quot;QIE&quot;, or &quot;Qualified Identity Escrow&quot; anywhere in public-facing copy. (The 9 frozen consensus byte strings inside the protocol — see invariant below — are not branding; they&#39;re protocol-internal hash inputs that predate the rename.)</li><li>Don&#39;t expand <code>zkqes</code> in headlines or branding except as one-shot context.</li></ul><h2 id="frozen-consensus-bytes-not-branding" tabindex="-1">Frozen consensus bytes (NOT branding) <a class="header-anchor" href="#frozen-consensus-bytes-not-branding" aria-label="Permalink to &quot;Frozen consensus bytes (NOT branding)&quot;">​</a></h2><p>A small set of string literals inside the codebase begin with <code>qkb-</code> and look like brand artifacts but are NOT branding. They are protocol-internal byte strings hashed (keccak256 / SHA-256 / Poseidon) into circuit publics, contract storage, or off-chain deterministically-derived values. Renaming them invalidates the V5 circuit + Phase B ceremony + every existing fixture.</p><p>The frozen tags are documented in <strong><code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code> §3</strong> — keep them; never touch. Each occurrence in code carries a freeze comment pointing back at that spec section. If you&#39;re writing a new amendment that needs a new domain-separation tag, name it with a <code>zkqes-</code> prefix; existing tags stay frozen.</p><h2 id="domains" tabindex="-1">Domains <a class="header-anchor" href="#domains" aria-label="Permalink to &quot;Domains&quot;">​</a></h2><p>The public-facing surface uses three subdomains under <code>zkqes.org</code>. Locked 2026-05-03.</p><table tabindex="0"><thead><tr><th>Subdomain</th><th>Purpose</th><th>Lifecycle</th></tr></thead><tbody><tr><td><code>zkqes.org</code> (root)</td><td>Pre-ceremony hero + ceremony recruitment CTA + three contribution paths (snarkjs local / VPS / Fly launcher)</td><td>Live pre-recruitment; persists post-launch as the project landing</td></tr><tr><td><code>app.zkqes.org</code></td><td>The actual register flow — <code>/ua/registerV5</code> + <code>/account/rotate</code>. Hosts the SPA. End users come here only after Phase B ceremony completes + Sepolia E2E §9.4 green</td><td>Live post-ceremony</td></tr><tr><td><code>docs.zkqes.org</code></td><td>VitePress-rendered docs from the <code>docs/</code> tree — install instructions, specs, ceremony attestations, SDK reference, this BRAND.md</td><td>Live pre-recruitment</td></tr><tr><td><code>prove.zkqes.org</code></td><td>Ceremony coordinator (R2-backed status feed + manifest hosting)</td><td>Live post-DNS migration; bucket name <code>prove-zkqes-org</code></td></tr></tbody></table><p>Old <code>prove.identityescrow.org</code> host + <code>prove-identityescrow-org</code> R2 bucket remain frozen as a read-only mirror for V3/V4 historical artifacts; new ceremony rounds publish at <code>prove.zkqes.org</code>.</p><p>The split exists because the three audiences are distinct: ceremony contributors (zkqes.org root), end users registering with their QES (app.zkqes.org, post-launch), and developers / integrators / researchers (docs.zkqes.org). Surfacing all three on one page would mute the call-to-action that matters at the current lifecycle stage.</p><h2 id="defensive-registrations" tabindex="-1">Defensive registrations <a class="header-anchor" href="#defensive-registrations" aria-label="Permalink to &quot;Defensive registrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>Status</th><th>Action</th></tr></thead><tbody><tr><td><code>zkqes.org</code></td><td>Live, canonical</td><td>Keep — primary public domain</td></tr><tr><td><code>identityescrow.org</code></td><td>Held (never published a working public surface)</td><td>No 301 needed at present; can be added later if any traffic appears</td></tr><tr><td><code>alik-eth/zkqes</code> (GitHub)</td><td>Live</td><td>Repo (renamed 2026-05-03 from <code>identityescroworg</code>); GitHub auto-redirects the old URL</td></tr><tr><td><code>zkqes.com</code></td><td>Open call</td><td>Recommended defensive buy + 301 → <code>zkqes.org</code></td></tr><tr><td><code>@zkqes</code> (npm)</td><td>Open call — <strong>claim before first publish</strong></td><td>Defensive squat + protocol scope</td></tr><tr><td><code>@qkb</code> (npm)</td><td>Open call (no publishes ever)</td><td>No action — names are not used after the rename</td></tr></tbody></table><h2 id="when-this-document-changes" tabindex="-1">When this document changes <a class="header-anchor" href="#when-this-document-changes" aria-label="Permalink to &quot;When this document changes&quot;">​</a></h2><p>This brand collapse is intentionally robust to future edits — the ship surface is single-name, the protocol is single-name, the domain is single-name. If founder later decides to introduce a sub-brand (e.g., a separate name for an EVM-native variant or a fork), it should land as a new noun under the same project, not a re-litigation of the three-tier split.</p><p>Do not edit this document without founder sign-off.</p><hr><h2 id="visual-language" tabindex="-1">Visual language <a class="header-anchor" href="#visual-language" aria-label="Permalink to &quot;Visual language&quot;">​</a></h2><p>The visual identity is <strong>civic-terminal</strong>: Curve.fi-era panel chrome (beige/grey paper, raised/inset 3D borders, dashed inner frames with floating legends) crossed with Ukraine + EU civic-document signals (four-bar civic stripe, official-form letterhead structure, embossed seals). Pure monospace type. Heavy use of ASCII art.</p><p>The aesthetic positions the project as bureaucratic-credible (this is a thing that interfaces with real-world legal trust services under eIDAS and Ukrainian DSP law) AND engineering-credible: the system is built on Groth16/Circom against real eIDAS trust-service infrastructure.</p><p><strong>Date locked:</strong> 2026-05-04 (replaces the prior civic-monumental direction shipped 2026-05-03 in #60). Decision references:</p><ul><li><code>docs/superpowers/specs/2026-05-04-zkqes-civic-terminal-rebrand-design.md</code> (v1 — landing-only)</li><li><code>docs/superpowers/specs/2026-05-04-zkqes-civic-terminal-v2-design.md</code> (v2 — full surface family)</li></ul><p><strong>Wireframe reference:</strong> Founder-curated Claude Design bundle, variant D (&quot;Curve router · dense&quot;). The marquee + 3-column data-grid layout is the canonical home shape; other surfaces inherit the same chrome grammar at appropriate density.</p><p><strong>Subdomain consistency:</strong> All three subdomains (<code>zkqes.org</code>, <code>docs.zkqes.org</code>, <code>app.zkqes.org</code>) consume the same token layer (<code>packages/web/src/styles/civic-terminal.css</code>). Cross-subdomain visual drift is a regression.</p><h2 id="type-stack" tabindex="-1">Type stack <a class="header-anchor" href="#type-stack" aria-label="Permalink to &quot;Type stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Typeface</th><th>Weights</th><th>CSS variable</th></tr></thead><tbody><tr><td>Display (h1, h2, h3, large numerics, brand mark)</td><td>VT323</td><td>400 only</td><td><code>--display</code></td></tr><tr><td>Body (paragraphs, log lines, form input, button labels, code)</td><td>IBM Plex Mono</td><td>400, 500, 600, 700</td><td><code>--mono</code></td></tr></tbody></table><p>Webfonts loaded via Google Fonts CDN with <code>font-display: swap</code>:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preconnect&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://fonts.googleapis.com&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> crossorigin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preconnect&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://fonts.gstatic.com&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> crossorigin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500;600;700&amp;family=VT323&amp;display=swap&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;stylesheet&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  crossorigin</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span></code></pre></div><p><code>crossorigin</code> is set on every <code>&lt;link&gt;</code> so the browser performs a CORS fetch (matches the server&#39;s <code>Access-Control-Allow-Origin: *</code> and deduplicates against later font-file CORS requests). <code>font-display: swap</code> is encoded in the URL query (<code>&amp;display=swap</code>) and produces a brief fallback-font flash on first paint instead of a blocked-render window.</p><p>Subresource Integrity hashes are NOT used: Google Fonts does not publish stable hashes for the dynamically-generated CSS (content varies by user-agent). Self-hosting the fonts (which would let us pin SRI) is a follow-up polish pass post-adoption, not load-bearing for the v0.6.x recruitment window.</p><p>VT323 size band: 22–72px. Below 22px VT323 renders fuzzy; below 18px do not use VT323 — fall through to <code>--mono</code> 600-weight. Body copy constrained to ≤65ch line length to mitigate monospace readability tax.</p><p>The prior civic-monumental type stack (EB Garamond + Inter Tight + JetBrains Mono) is deprecated as of 2026-05-04. Existing references in <code>packages/web/index.html</code> <code>&lt;link&gt;</code> preconnects must be removed <strong>in the same commit that adds VT323 + Plex Mono</strong> — atomic transition, no dead-preconnect window.</p><h2 id="component-grammar" tabindex="-1">Component grammar <a class="header-anchor" href="#component-grammar" aria-label="Permalink to &quot;Component grammar&quot;">​</a></h2><p>The visual surface is built from a stable set of class-based primitives. These are CSS classes consumed by JSX <code>className</code> strings; they are NOT React components by default. If a future broader adoption surfaces a need for component extraction, that&#39;s a follow-up.</p><p><strong>Source of truth:</strong> <code>packages/web/src/styles/civic-terminal.css</code>. The class namespace is stable; new primitives require a BRAND.md amendment + a corresponding entry in the rebrand spec.</p><p><strong>Token table:</strong> see v1 spec §4.1 for the full CSS-variable reference (<code>--ct-paper</code> / <code>--ct-ink</code> / <code>--ua-blue</code> / <code>--ua-yellow</code> / <code>--eu-blue</code> / <code>--eu-gold</code> / <code>--ok</code> / <code>--warn</code> / <code>--err</code> / <code>--hilite</code> + 5 more).</p><p><strong>Primary primitives:</strong></p><ul><li><code>.ct-panel</code> (solid panel chrome) + <code>.ct-panel--raised</code> / <code>.ct-panel--inset</code> (3D variants)</li><li><code>.ct-field</code> (dashed inner frame) + <code>.ct-legend</code> (floating label)</li><li><code>.ct-tab</code> / <code>.ct-tab--off</code> (Curve-era tabs)</li><li><code>.ct-btn</code> + variants (<code>--primary</code>, <code>--ua</code>, <code>--eu</code>, <code>--ghost</code>, <code>--sm</code>, <code>--lg</code>)</li><li><code>.ct-civic-stripe</code> (4-bar UA + EU stripe — decorative, <code>aria-hidden</code>)</li><li><code>.ct-flag-ua</code> / <code>.ct-flag-eu</code> (16×24 glyphs)</li><li><code>.ct-tag</code> + variants (<code>--ua</code> / <code>--eu</code> / <code>--ok</code> / <code>--warn</code> / <code>--err</code>)</li><li><code>.ct-seal</code> (rotated 96×96 civic seal)</li><li><code>.ct-cert-no</code> / <code>.ct-kicker</code> (cert-number / eyebrow text styles)</li><li><code>.ct-ascii</code> / <code>.ct-ascii--dense</code> (ASCII art containers)</li><li><code>.ct-log</code> / <code>.ct-row</code> / <code>.ct-row-h</code> / <code>.ct-stack</code> / <code>.ct-grid-2</code> / <code>.ct-grid-3</code> (layout helpers)</li></ul><p>Adding a new primitive is a BRAND.md amendment + a CSS edit + a spec entry.</p><h2 id="surface-grammar-v2-amendment-2026-05-04" tabindex="-1">Surface grammar (v2 amendment, 2026-05-04) <a class="header-anchor" href="#surface-grammar-v2-amendment-2026-05-04" aria-label="Permalink to &quot;Surface grammar (v2 amendment, 2026-05-04)&quot;">​</a></h2><p>The civic-terminal grammar applies across four user-facing surface families. Each family has a fixed body shape; the chrome (marquee + footer ribbon) is shared.</p><table tabindex="0"><thead><tr><th>Surface family</th><th>Body shape</th><th>Why</th></tr></thead><tbody><tr><td>Landing</td><td>3-col shell (variant D)</td><td>gateway feel; multiple peripheral concerns visible at once</td></tr><tr><td><code>/ceremony</code></td><td>3-col shell</td><td>data-rich dashboard; chain + recruit-cards + verify-widget cleanly split</td></tr><tr><td><code>/register</code></td><td>single long form (max-width 720px, 6 sections)</td><td>6-step flow needs reading-order; columns would compete for attention</td></tr><tr><td><code>/account/rotate</code></td><td>single long form (max-width 720px, 3 sections)</td><td>symmetric with <code>/register</code>; reused for visual consistency</td></tr><tr><td><code>/verify</code></td><td>3-col shell</td><td>inspector/explorer (paste + result); siblings with <code>/ceremony</code></td></tr></tbody></table><p>Body shapes are immutable per surface family. Token grammar (palette, type, <code>.ct-*</code> primitives) is consistent across all surfaces. Only the body layout differs.</p><h3 id="phase-led-states" tabindex="-1">Phase-LED states <a class="header-anchor" href="#phase-led-states" aria-label="Permalink to &quot;Phase-LED states&quot;">​</a></h3><p>The marquee phase indicator uses a coloured LED + text:</p><table tabindex="0"><thead><tr><th>Phase</th><th>LED color</th><th>Text</th></tr></thead><tbody><tr><td><code>recruiting</code></td><td>yellow ●</td><td>recruiting</td></tr><tr><td><code>ceremony-live</code></td><td>green ●</td><td>ceremony-live</td></tr><tr><td><code>live</code></td><td>blue ●</td><td>live</td></tr></tbody></table><p>The LED has <code>aria-label=&quot;phase: &lt;phase&gt;&quot;</code> so the colour is informational, not decorative. <code>prefers-reduced-motion: reduce</code> replaces the pulse animation with a static dot.</p><h3 id="footer-ribbon" tabindex="-1">Footer ribbon <a class="header-anchor" href="#footer-ribbon" aria-label="Permalink to &quot;Footer ribbon&quot;">​</a></h3><p><code>{BUILD_SHA_7} · {BUILD_DATE} · zkqes.org</code> — locked 2026-05-04. Build-time <code>VITE_BUILD_SHA</code> (7-char SHA) + <code>VITE_BUILD_DATE</code> (ISO date) env vars. Renders on every surface family.</p><h3 id="frozen-marketer-locked-copy" tabindex="-1">Frozen marketer-locked copy <a class="header-anchor" href="#frozen-marketer-locked-copy" aria-label="Permalink to &quot;Frozen marketer-locked copy&quot;">​</a></h3><p>These strings are NOT to be rephrased. Lifted into code as-is from v1 spec §3 + v2 spec §3 / §4.</p><table tabindex="0"><thead><tr><th>Surface</th><th>Element</th><th>Copy</th></tr></thead><tbody><tr><td>Landing</td><td>Binding-statement preview</td><td>&quot;Holders sign a binding statement that names a wallet, and prove the signature in zk — without disclosing it.&quot;</td></tr><tr><td>Landing</td><td>Marquee count, recruiting</td><td><code>round 0 of {TOTAL}</code> — or <code>round — of —</code> if <code>totalRounds === 0</code> (HN-screenshot mitigation)</td></tr><tr><td>Landing</td><td>Disabled-tab tooltip</td><td><code>Available after trusted setup ceremony + Base Sepolia testnet deploy</code></td></tr><tr><td>Landing</td><td>Marquee right sidebar, recruiting</td><td><code>awaiting first contributor (10 needed · ≥32 GB RAM or cloud equivalent)</code></td></tr><tr><td><code>/ceremony</code></td><td>Coord attribution</td><td><code>COORD: alik.eth · DM for round assignment</code></td></tr><tr><td>App routes</td><td>PreviewModeBanner</td><td><code>PREVIEW MODE — ceremony in progress · verifications use stub verifier · proofs are NOT trusted for production</code></td></tr></tbody></table><p>Marketer reviews any new public-facing copy before lock. The v2 spec PR has the marketer review trail.</p>`,66)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
